17→@Service
18→@Slf4j
19→public class VersionSnapshotServiceImpl extends ServiceImpl<CollabspaceVersionSnapshotMapper, CollabspaceVersionSnapshotEntity> implements IVersionSnapshotService {
20→    @Resource
21→    CollabspaceVersionSnapshotMapper collabspaceVersionSnapshotMapper;
22→
23→    @Override
24→    public CollabspaceVersionSnapshotEntity getByName(String name, Long nodeId) {
25→        QueryWrapper<CollabspaceVersionSnapshotEntity> queryWrapper = new QueryWrapper<>();
26→        queryWrapper.lambda().eq(CollabspaceVersionSnapshotEntity::getSnapshotName, name)
27→                .eq(CollabspaceVersionSnapshotEntity::getNodeId, nodeId);
28→        List<CollabspaceVersionSnapshotEntity> list = collabspaceVersionSnapshotMapper.selectList(queryWrapper);
29→        return list.isEmpty() ? null : list.getFirst();
30→    }
31→
32→    @Override
33→    public List<CollabspaceVersionSnapshotEntity> getByNodeId(Long spaceNodeId, Integer status) {
34→        QueryWrapper<CollabspaceVersionSnapshotEntity> queryWrapper = new QueryWrapper<>();
35→        queryWrapper.lambda().eq(CollabspaceVersionSnapshotEntity::getSnapshotStatus, status)
36→                .eq(CollabspaceVersionSnapshotEntity::getNodeId, spaceNodeId);
37→        return collabspaceVersionSnapshotMapper.selectList(queryWrapper);
38→    }
39→
40→    @Override
41→    public List<CollabspaceVersionSnapshotEntity> getOverTimeSnapshotList() {
42→        LocalDateTime threshold = LocalDateTime.now().minusDays(30);
43→
44→        return this.list(new LambdaQueryWrapper<CollabspaceVersionSnapshotEntity>()
45→                .eq(CollabspaceVersionSnapshotEntity::getSnapshotStatus, VersionSnapshotStatusEnum.DISABLED.getValue())
46→                .lt(CollabspaceVersionSnapshotEntity::getUpdatedAt, threshold)
47→        );
48→    }
49→}
