import com.baomidou.mybatisplus.extension.service.impl.ServiceImpl;
import com.yottastudios.ns.collabspace.workspace.entity.SpaceNodeMigrationTaskEntity;
import com.yottastudios.ns.collabspace.workspace.mapper.SpaceNodeMigrationTaskMapper;
import com.yottastudios.ns.collabspace.workspace.service.ISpaceNodeMigrationTaskService;
import org.springframework.stereotype.Service;

import java.util.List;

@Service
public class SpaceNodeMigrationTaskServiceImpl extends ServiceImpl<SpaceNodeMigrationTaskMapper, SpaceNodeMigrationTaskEntity> implements ISpaceNodeMigrationTaskService {
    @Override
    public SpaceNodeMigrationTaskEntity getByTaskId(String taskId) {
        return this.lambdaQuery()
                .eq(SpaceNodeMigrationTaskEntity::getTaskId, taskId)
                .one();
    }

    @Override
    public List<SpaceNodeMigrationTaskEntity> listByBatchId(String batchId) {
        return this.lambdaQuery()
                .eq(SpaceNodeMigrationTaskEntity::getBatchId, batchId)
                .list();
    }
}

