    @Override
    public List<CollabspaceVersionSnapshotEntity> getOverTimeSnapshotList() {
        LocalDateTime threshold = LocalDateTime.now().minusDays(30);

        return this.list(new LambdaQueryWrapper<CollabspaceVersionSnapshotEntity>()
                .eq(CollabspaceVersionSnapshotEntity::getSnapshotStatus, VersionSnapshotStatusEnum.DISABLED.getValue())
                .lt(CollabspaceVersionSnapshotEntity::getUpdatedAt, threshold)
        );
    }

    @Override
    public void disableByNodeId(Long nodeId) {
        this.lambdaUpdate()
                .eq(CollabspaceVersionSnapshotEntity::getNodeId, nodeId)
                .eq(CollabspaceVersionSnapshotEntity::getSnapshotStatus, VersionSnapshotStatusEnum.ENABLED.getValue())
                .set(CollabspaceVersionSnapshotEntity::getSnapshotStatus, VersionSnapshotStatusEnum.DISABLED.getValue())
                .update();
    }
}
